def gaelic_to_anglicized(gaelic_name):
    # Simple mapping for this specific case
    anglicized_forms = {
        'Mac Dhuibhshíthe': 'Macfie',
        'MacDhubhShìth': 'MacFie',
        'Mac Phee': 'MacPhee',
        'Mac Phie': 'MacPhie'
    }
    return anglicized_forms.get(gaelic_name, "Unknown form")

# Example usage
print(gaelic_to_anglicized('Mac Dhuibhshíthe'))  # Output: Macfie
